query_and_export.query11:
SELECT DISTINCT INHTYCDE, INHLDCDE FROM CTXPRWDTA.OPROPN WHERE INHLDCDE IN( SELECT
                INHLDCDE FROM CTXPRWDTA.OPRPHD WHERE MMUOMCDE ='PR' AND GNUPDDTE BETWEEN ? AND ?
                )AND INHTYCDE IN('17-C10','13-X20') AND OPOPNSTS ='060' ORDER BY INHTYCDE, INHLDCDE
